        public DateTime? ReturnDate { get; set; }

        [Display(Name = "Daily Rate")]
        [Range(0.01, 999.99, ErrorMessage = "Daily rate must be between $0.01 and $999.99.")]
        [DataType(DataType.Currency)]
        public decimal DailyRate { get; set; }

        [Display(Name = "Late Fee")]
        [DataType(DataType.Currency)]
        public decimal LateFee { get; set; }

        /// <summary>
        /// Damage charge assessed on return (separate from late fees).
        /// </summary>
        [Display(Name = "Damage Charge")]
        [DataType(DataType.Currency)]
        public decimal DamageCharge { get; set; }

        /// <summary>
        /// Current status of the rental.
        /// </summary>
        [Display(Name = "Status")]
        public RentalStatus Status { get; set; }

        /// <summary>
        /// Total cost = (rental days * daily rate) + late fee.
        /// </summary>
        [Display(Name = "Total Cost")]
        public decimal TotalCost
        {
            get
            {
                var endDate = ReturnDate ?? DateTime.Today;
                var days = Math.Max(1, (int)Math.Ceiling((endDate - RentalDate).TotalDays));
                return (days * DailyRate) + LateFee + DamageCharge;
            }
        }

        /// <summary>
        /// Number of days overdue (0 if not overdue).
        /// </summary>
        public int DaysOverdue
        {
            get
            {
                if (Status == RentalStatus.Returned)
                    return ReturnDate.HasValue && ReturnDate.Value > DueDate
                        ? (int)Math.Ceiling((ReturnDate.Value - DueDate).TotalDays)
                        : 0;

                return DateTime.Today > DueDate
                    ? (int)Math.Ceiling((DateTime.Today - DueDate).TotalDays)
                    : 0;
            }
        }

        /// <summary>
        /// Whether this rental is currently overdue.
        /// </summary>
        public bool IsOverdue =>
            Status != RentalStatus.Returned && DateTime.Today > DueDate;
    }

    /// <summary>
    /// Rental lifecycle status.
    /// </summary>
    public enum RentalStatus
    {
        [Display(Name = "Active")]
        Active = 1,

        [Display(Name = "Overdue")]
        Overdue = 2,

        [Display(Name = "Returned")]
        Returned = 3
    }
}

