// Donut chart
(function() {
    var data = [@Model.LowRiskCount, @Model.MediumRiskCount, @Model.HighRiskCount, @Model.CriticalRiskCount];
    var colors = ['#17bf63','#ffad1f','#f45d22','#e0245e'];
    var canvas = document.getElementById('donutChart');
    var ctx = canvas.getContext('2d');
    var total = data.reduce(function(a,b){return a+b;},0);
    if (total === 0) return;
    var cx = 100, cy = 100, r = 80, ir = 50;
    var angle = -Math.PI/2;
    for (var i = 0; i < data.length; i++) {
        var slice = (data[i]/total) * Math.PI * 2;
        ctx.beginPath();
        ctx.arc(cx, cy, r, angle, angle + slice);
        ctx.arc(cx, cy, ir, angle + slice, angle, true);
        ctx.closePath();
        ctx.fillStyle = colors[i];
        ctx.fill();
        angle += slice;
    }
    ctx.beginPath();
    ctx.arc(cx, cy, ir - 2, 0, Math.PI * 2);
    ctx.fillStyle = '#192734';
    ctx.fill();
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 20px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(total, cx, cy + 7);
})();

// Filter buttons
document.querySelectorAll('.filter-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
        document.querySelectorAll('.filter-btn').forEach(function(b){b.classList.remove('active');});
        btn.classList.add('active');
        var filter = btn.getAttribute('data-filter');
        document.querySelectorAll('#riskTable tbody tr').forEach(function(row) {
            if (filter === 'all' || row.getAttribute('data-level') === filter)
                row.style.display = '';
            else
                row.style.display = 'none';
        });
    });
});

// Detail modal
function showDetail(id) {
    fetch('/ChurnPredictor/Customer/' + id)
        .then(function(r){return r.json();})
        .then(function(d) {
            if (!d.success) return;
            var p = d.profile;
            document.getElementById('modalTitle').textContent = p.CustomerName + ' — ' + p.RiskLevel + ' Risk';
            // Gauge
            drawGauge(p.RiskScore);
            document.getElementById('gaugeLabel').textContent = 'Risk Score: ' + p.RiskScore + '/100';
            // Factors
            var factors = [
                {name:'Recency', val:p.Factors.RecencyScore},
                {name:'Frequency Decline', val:p.Factors.FrequencyDeclineScore},
                {name:'Engagement', val:p.Factors.EngagementScore},
                {name:'Late Returns', val:p.Factors.LateReturnScore},
                {name:'Genre Diversity', val:p.Factors.DiversityScore}
            ];
            var html = '';
            factors.forEach(function(f) {
                var color = f.val < 30 ? '#17bf63' : f.val < 60 ? '#ffad1f' : '#e0245e';
                html += '<div class="factor-bar"><div class="factor-label"><span>'+f.name+'</span><span>'+Math.round(f.val)+'</span></div><div class="bar-bg"><div class="bar-fill" style="width:'+f.val+'%;background:'+color+'"></div></div></div>';
            });
            document.getElementById('modalFactors').innerHTML = html;
            // Actions
            var actHtml = '';
            (p.RetentionActions || []).forEach(function(a) { actHtml += '<li>'+a+'</li>'; });
            document.getElementById('modalActions').innerHTML = actHtml;
            document.getElementById('detailModal').classList.add('open');
        });
}

function drawGauge(score) {
    var canvas = document.getElementById('gaugeCanvas');
    var ctx = canvas.getContext('2d');
    ctx.clearRect(0,0,180,100);
    var cx = 90, cy = 90, r = 70;
    // Background arc
    ctx.beginPath();
    ctx.arc(cx, cy, r, Math.PI, 0);
    ctx.lineWidth = 14;
    ctx.strokeStyle = '#2d3741';
    ctx.stroke();
    // Score arc
    var pct = score / 100;
    var endAngle = Math.PI + pct * Math.PI;
    var color = score < 25 ? '#17bf63' : score < 50 ? '#ffad1f' : score < 75 ? '#f45d22' : '#e0245e';
    ctx.beginPath();
    ctx.arc(cx, cy, r, Math.PI, endAngle);
    ctx.lineWidth = 14;
    ctx.strokeStyle = color;
    ctx.lineCap = 'round';
    ctx.stroke();
    // Score text
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 24px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(Math.round(score), cx, cy - 10);
}

function closeModal() {
    document.getElementById('detailModal').classList.remove('open');
}

document.getElementById('detailModal').addEventListener('click', function(e) {
    if (e.target === this) closeModal();
});
</script>
</body>
</html>

