            DateTime now)
        {
            var recs = new List<ClvRecommendation>();

            // 1. Upsell basic members with high activity
            var upsellCandidates = profiles
                .Where(p => p.Membership == MembershipType.Basic && p.TotalRentals > 5)
                .ToList();
            if (upsellCandidates.Any())
            {
